function switch_view(e){e.checked?(document.getElementById("tldr-content").style.display="block",document.getElementById("content").style.display="none"):(document.getElementById("tldr-content").style.display="none",document.getElementById("content").style.display="block")}function switch_review(e){review_num=e.id.split("_")[2],titles=document.getElementById("review_titles"),content=document.getElementById("content");for(let t of titles.children)t.id===e.id?t.className="active-review-title":t.className="";for(let e of content.children)e.id.includes(review_num)?e.className="":e.className="hidden"}